const WebSocket = require('ws');
const crypto = require('crypto');
const https = require('https');
const fs = require('fs');

// Secure TLS configuration
const server = https.createServer({
  cert: fs.readFileSync(process.env.TLS_CERT_PATH),
  key: fs.readFileSync(process.env.TLS_KEY_PATH),
  minVersion: 'TLSv1.2',
});

const wss = new WebSocket.Server({ server, maxPayload: 4096 });

// Game state
const gameState = {
  players: new Map(),
  units: new Map(),
  buildings: new Map(),
  mapWidth: 1000,
  mapHeight: 1000,
};

// Session and anti-replay tracking
const activeSessions = new Map();
const usedNonces = new Map(); // nonce -> expiry timestamp
const NONCE_EXPIRY_MS = 30000; // 30 seconds
const MAX_NONCES_PER_PLAYER = 500;
const COMMAND_RATE_LIMIT = 20; // commands per second
const AUTH_TOKEN_SECRET = process.env.AUTH_TOKEN_SECRET;

if (!AUTH_TOKEN_SECRET) {
  console.error('AUTH_TOKEN_SECRET environment variable is required');
  process.exit(1);
}

// Allowed command types (explicit allowlist)
const ALLOWED_COMMANDS = new Set(['build', 'attack', 'move']);

// Allowed building types
const ALLOWED_BUILDING_TYPES = new Set(['barracks', 'factory', 'tower', 'wall', 'base']);

// Allowed unit types
const ALLOWED_UNIT_TYPES = new Set(['soldier', 'tank', 'scout']);

// Periodically clean expired nonces
setInterval(() => {
  const now = Date.now();
  for (const [nonce, expiry] of usedNonces.entries()) {
    if (now > expiry) {
      usedNonces.delete(nonce);
    }
  }
}, 10000);

function verifyAuthToken(token) {
  if (!token || typeof token !== 'string') return null;

  try {
    const parts = token.split('.');
    if (parts.length !== 3) return null;

    const [headerB64, payloadB64, signatureB64] = parts;

    const expectedSignature = crypto
      .createHmac('sha256', AUTH_TOKEN_SECRET)
      .update(`${headerB64}.${payloadB64}`)
      .digest('base64url');

    if (!crypto.timingSafeEqual(Buffer.from(signatureB64), Buffer.from(expectedSignature))) {
      return null;
    }

    const payload = JSON.parse(Buffer.from(payloadB64, 'base64url').toString());

    if (payload.exp && Date.now() / 1000 > payload.exp) {
      return null;
    }

    if (!payload.playerId || typeof payload.playerId !== 'string') {
      return null;
    }

    return payload;
  } catch {
    return null;
  }
}

function validateNonce(nonce, playerId) {
  if (!nonce || typeof nonce !== 'string') return false;
  if (nonce.length < 16 || nonce.length > 64) return false;
  if (!/^[a-zA-Z0-9+/=_-]+$/.test(nonce)) return false;

  const nonceKey = `${playerId}:${nonce}`;

  if (usedNonces.has(nonceKey)) {
    return false; // Replay detected
  }

  // Count nonces for this player
  let playerNonceCount = 0;
  for (const key of usedNonces.keys()) {
    if (key.startsWith(`${playerId}:`)) {
      playerNonceCount++;
    }
  }

  if (playerNonceCount >= MAX_NONCES_PER_PLAYER) {
    return false;
  }

  usedNonces.set(nonceKey, Date.now() + NONCE_EXPIRY_MS);
  return true;
}

function validateCoordinates(x, y) {
  return (
    typeof x === 'number' &&
    typeof y === 'number' &&
    Number.isFinite(x) &&
    Number.isFinite(y) &&
    x >= 0 &&
    x <= gameState.mapWidth &&
    y >= 0 &&
    y <= gameState.mapHeight
  );
}

function validateUnitId(unitId) {
  return typeof unitId === 'string' && /^[a-zA-Z0-9_-]{1,36}$/.test(unitId);
}

function validateBuildingType(type) {
  return typeof type === 'string' && ALLOWED_BUILDING_TYPES.has(type);
}

function checkRateLimit(session) {
  const now = Date.now();
  session.commandTimestamps = session.commandTimestamps.filter((t) => now - t < 1000);

  if (session.commandTimestamps.length >= COMMAND_RATE_LIMIT) {
    return false;
  }

  session.commandTimestamps.push(now);
  return true;
}

function validateCommand(data) {
  if (!data || typeof data !== 'object') return { valid: false, reason: 'Invalid message format' };
  if (!ALLOWED_COMMANDS.has(data.type)) return { valid: false, reason: 'Unknown command type' };
  if (!data.nonce) return { valid: false, reason: 'Missing nonce' };

  switch (data.type) {
    case 'build': {
      if (!validateBuildingType(data.buildingType)) {
        return { valid: false, reason: 'Invalid building type' };
      }
      if (!validateCoordinates(data.x, data.y)) {
        return { valid: false, reason: 'Invalid coordinates' };
      }
      return { valid: true };
    }

    case 'attack': {
      if (!validateUnitId(data.unitId)) {
        return { valid: false, reason: 'Invalid unit ID' };
      }
      if (!validateUnitId(data.targetId)) {
        return { valid: false, reason: 'Invalid target ID' };
      }
      return { valid: true };
    }

    case 'move': {
      if (!validateUnitId(data.unitId)) {
        return { valid: false, reason: 'Invalid unit ID' };
      }
      if (!validateCoordinates(data.x, data.y)) {
        return { valid: false, reason: 'Invalid coordinates' };
      }
      return { valid: true };
    }

    default:
      return { valid: false, reason: 'Unknown command type' };
  }
}

function checkOwnership(playerId, unitId) {
  const unit = gameState.units.get(unitId);
  return unit && unit.ownerId === playerId;
}

function processCommand(playerId, command) {
  const result = { success: false, type: command.type };

  switch (command.type) {
    case 'build': {
      const buildingId = crypto.randomUUID();

      // Check if location is available (simplified collision check)
      for (const [, building] of gameState.buildings) {
        const dx = Math.abs(building.x - command.x);
        const dy = Math.abs(building.y - command.y);
        if (dx < 5 && dy < 5) {
          result.reason = 'Location occupied';
          return result;
        }
      }

      const building = {
        id: buildingId,
        ownerId: playerId,
        type: command.buildingType,
        x: command.x,
        y: command.y,
        health: 100,
        createdAt: Date.now(),
      };

      gameState.buildings.set(buildingId, building);
      result.success = true;
      result.buildingId = buildingId;
      result.building = { id: buildingId, type: building.type, x: building.x, y: building.y };
      break;
    }

    case 'attack': {
      if (!checkOwnership(playerId, command.unitId)) {
        result.reason = 'Unit not owned by player';
        return result;
      }

      const attackingUnit = gameState.units.get(command.unitId);
      const target =
        gameState.units.get(command.targetId) || gameState.buildings.get(command.targetId);

      if (!target) {
        result.reason = 'Target not found';
        return result;
      }

      if (target.ownerId === playerId) {
        result.reason = 'Cannot attack own units';
        return result;
      }

      // Calculate distance for range check
      const dx = target.x - attackingUnit.x;
      const dy = target.y - attackingUnit.y;
      const distance = Math.sqrt(dx * dx + dy * dy);

      const attackRange = attackingUnit.range || 10;
      if (distance > attackRange) {
        result.reason = 'Target out of range';
        return result;
      }

      const damage = attackingUnit.attack || 10;
      target.health -= damage;

      result.success = true;
      result.damage = damage;
      result.targetHealth = target.health;

      if (target.health <= 0) {
        gameState.units.delete(command.targetId);
        gameState.buildings.delete(command.targetId);
        result.targetDestroyed = true;
      }
      break;
    }

    case 'move': {
      if (!checkOwnership(playerId, command.unitId)) {
        result.reason = 'Unit not owned by player';
        return result;
      }

      const unit = gameState.units.get(command.unitId);
      const moveDx = command.x - unit.x;
      const moveDy = command.y - unit.y;
      const moveDistance = Math.sqrt(moveDx * moveDx + moveDy * moveDy);

      const maxMoveDistance = unit.speed || 50;
      if (moveDistance > maxMoveDistance) {
        // Clamp to max distance
        const ratio = maxMoveDistance / moveDistance;
        unit.x += moveDx * ratio;
        unit.y += moveDy * ratio;
      } else {
        unit.x = command.x;
        unit.y = command.y;
      }

      result.success = true;
      result.newX = unit.x;
      result.newY = unit.y;
      break;
    }
  }

  return result;
}

function broadcastToOthers(senderPlayerId, message) {
  for (const [, session] of activeSessions) {
    if (session.playerId !== senderPlayerId && session.ws.readyState === WebSocket.OPEN) {
      session.ws.send(JSON.stringify(message));
    }
  }
}

wss.on('connection', (ws, req) => {
  let sessionId = null;
  let authenticated = false;
  let playerId = null;

  // Authentication timeout - must authenticate within 5 seconds
  const authTimeout = setTimeout(() => {
    if (!authenticated) {
      ws.close(4001, 'Authentication timeout');
    }
  }, 5000);

  ws.on('message', (rawMessage) => {
    let data;
    try {
      if (rawMessage.length > 4096) {
        ws.send(JSON.stringify({ error: 'Message too large' }));
        return;
      }

      data = JSON.parse(rawMessage.toString('utf8'));
    } catch {
      ws.send(JSON.stringify({ error: 'Invalid JSON' }));
      return;
    }

    // Handle authentication
    if (!authenticated) {
      if (data.type !== 'auth' || typeof data.token !== 'string') {
        ws.close(4002, 'Authentication required');
        return;
      }

      const tokenPayload = verifyAuthToken(data.token);
      if (!tokenPayload) {
        ws.close(4003, 'Invalid authentication token');
        return;
      }

      clearTimeout(authTimeout);
      authenticated = true;
      playerId = tokenPayload.playerId;
      sessionId = crypto.randomUUID();

      // Disconnect existing session for this player (prevent session duplication)
      for (const [existingSessionId, existingSession] of activeSessions) {
        if (existingSession.playerId === playerId) {
          existingSession.ws.close(4004, 'Session replaced');
          activeSessions.delete(existingSessionId);
        }
      }

      const session = {
        sessionId,
        playerId,
        ws,
        commandTimestamps: [],
        connectedAt: Date.now(),
      };

      activeSessions.set(sessionId, session);

      // Initialize player in game state if new
      if (!gameState.players.has(playerId)) {
        const spawnX = Math.random() * gameState.mapWidth;
        const spawnY = Math.random() * gameState.mapHeight;

        gameState.players.set(playerId, {
          id: playerId,
          resources: 1000,
          spawnX,
          spawnY,
        });

        // Give starting unit
        const startUnitId = crypto.randomUUID();
        gameState.units.set(startUnitId, {
          id: startUnitId,
          ownerId: playerId,
          type: 'scout',
          x: spawnX,
          y: spawnY,
          health: 100,
          attack: 10,
          range: 10,
          speed: 50,
        });
      }

      ws.send(
        JSON.stringify({
          type: 'auth_success',
          sessionId,
          playerId,
          gameState: getPlayerVisibleState(playerId),
        })
      );

      console.log(`Player ${playerId} connected with session ${sessionId}`);
      return;
    }

    // Authenticated command processing
    const session = activeSessions.get(sessionId);
    if (!session) {
      ws.close(4005, 'Session not found');
      return;
    }

    // Rate limiting
    if (!checkRateLimit(session)) {
      ws.send(JSON.stringify({ error: 'Rate limit exceeded', type: 'error' }));
      return;
    }

    // Validate command structure
    const validation = validateCommand(data);
    if (!validation.valid) {
      ws.send(JSON.stringify({ error: validation.reason, type: 'error' }));
      return;
    }

    // Anti-replay: validate nonce
    if (!validateNonce(data.nonce, playerId)) {
      ws.send(
        JSON.stringify({ error: 'Invalid or replayed nonce. Generate a fresh nonce per command.', type: 'error' })
      );
      return;
    }

    // Process the command
    const result = processCommand(playerId, data);

    // Send result to the commanding player
    ws.send(
      JSON.stringify({
        type: 'command_result',
        commandType: data.type,
        ...result,
      })
    );

    // Broadcast relevant state changes to other players
    if (result.success) {
      broadcastToOthers(playerId, {
        type: 'game_event',
        eventType: data.type,
        playerId,
        result: sanitizeResultForBroadcast(result, data),
      });
    }
  });

  ws.on('close', () => {
    clearTimeout(authTimeout);
    if (sessionId) {
      activeSessions.delete(sessionId);
      console.log(`Player ${playerId} disconnected (session ${sessionId})`);
    }
  });

  ws.on('error', (err) => {
    console.error(`WebSocket error for player ${playerId}:`, err.message);
    if (sessionId) {
      activeSessions.delete(sessionId);
    }
  });
});

function getPlayerVisibleState(playerId) {
  const playerUnits = [];
  const playerBuildings = [];

  for (const [, unit] of gameState.units) {
    if (unit.ownerId === playerId) {
      playerUnits.push({ id: unit.id, type: unit.type, x: unit.x, y: unit.y, health: unit.health });
    }
  }

  for (const [, building] of gameState.buildings) {
    if (building.ownerId === playerId) {
      playerBuildings.push({
        id: building.id,
        type: building.type,
        x: building.x,
        y: building.y,
        health: building.health,
      });
    }
  }

  const player = gameState.players.get(playerId);

  return {
    resources: player ? player.resources : 0,
    units: playerUnits,
    buildings: playerBuildings,
    mapWidth: gameState.mapWidth,
    mapHeight: gameState.mapHeight,
  };
}

function sanitizeResultForBroadcast(result, command) {
  // Only include information that other players should see
  const sanitized = { type: command.type };

  switch (command.type) {
    case 'build':
      if (result.building) {
        sanitized.building = result.building;
      }
      break;
    case 'attack':
      sanitized.targetDestroyed = result.targetDestroyed || false;
      break;
    case 'move':
      sanitized.unitId = command.unitId;
      sanitized.newX = result.newX;
      sanitized.newY = result.newY;
      break;
  }

  return sanitized;
}

const PORT = parseInt(process.env.PORT, 10) || 8443;
server.listen(PORT, () => {
  console.log(`Secure RTS game server running on port ${PORT}`);
});